const now = new Date();
const today = now.toISOString().slice(0, 10);
const due = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
const runId = `N8N-STOCK-MFG-${Date.now()}`;
return [{ json: { runId, company: 'Thái Duy Digital', parentWarehouse: 'All Warehouses - TDD', postingDate: today, dueDate: due, plannedStart: `${today} 08:00:00`, customerName: `${runId} KH finished goods`, itemGroup: `${runId} Nhóm SX cơ bản`, rawWarehouseName: `${runId} Raw WH`, wipWarehouseName: `${runId} WIP WH`, fgWarehouseName: `${runId} FG WH`, rawA: `${runId} Raw A`, rawB: `${runId} Raw B`, finished: `${runId} Finished Good`, receiptRawA: 5, receiptRawB: 4, consumeRawA: 2, consumeRawB: 1, finishedQty: 1, rawARate: 30, rawBRate: 20, finishedRate: 95, accounts: { receivable: '1310 - Debtors - TDD', sales: '4110 - Sales - TDD' } } }];

const ctx = $('Build MFG Context').first().json;
const wo = $('Get MFG Work Order After').first().json;
const bins = $('Verify MFG Finished Bin').all().map(i => i.json);
const sle = $('Verify MFG Finished SLE').all().map(i => i.json);
const fgWh = $('Create MFG FG Warehouse').first().json.name;
const fgQty = Number(bins.find(row => row.warehouse === fgWh)?.actual_qty ?? 0);
const manufactureRows = sle.filter(row => row.voucher_no === $('Create MFG Manufacture').first().json.name);
const saleRows = sle.filter(row => row.voucher_no === $('Create MFG Sale').first().json.name);
const status = Number($('Submit MFG BOM').first().json.docstatus) === 1 && Number(wo.docstatus) === 1 && Number($('Submit MFG Transfer').first().json.docstatus) === 1 && Number($('Submit MFG Manufacture').first().json.docstatus) === 1 && Number($('Submit MFG Sale').first().json.docstatus) === 1 && fgQty === 0 && manufactureRows.some(row => Number(row.actual_qty) === ctx.finishedQty) && saleRows.some(row => Number(row.actual_qty) === -ctx.finishedQty);
const text = JSON.stringify({ wo: { name: wo.name, docstatus: wo.docstatus, status: wo.status, produced_qty: wo.produced_qty, material_transferred_for_manufacturing: wo.material_transferred_for_manufacturing }, bins, sle });
const securityFindings = ['api key', 'api_secret', 'authorization', 'token ', 'password'].filter(term => text.toLowerCase().includes(term));
return [{ json: { status: status && securityFindings.length === 0 ? 'passed' : 'failed', runId: ctx.runId, bom: $('Create MFG BOM').first().json.name, workOrder: wo.name, workOrderDocstatus: wo.docstatus, workOrderStatus: wo.status, workOrderProducedQty: wo.produced_qty, workOrderTransferredQty: wo.material_transferred_for_manufacturing, transferEntry: $('Create MFG Transfer').first().json.name, manufactureEntry: $('Create MFG Manufacture').first().json.name, saleInvoice: $('Submit MFG Sale').first().json.name, finishedItem: $('Create MFG Finished').first().json.name, finishedWarehouse: fgWh, finishedQtyAfterSale: fgQty, finishedLedgerRows: sle.length, manufactureLedgerActualQty: manufactureRows.map(row => row.actual_qty), saleLedgerActualQty: saleRows.map(row => row.actual_qty), securityFindings } }];
